var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_ON","text":{"KOREA":"카르멘! 네가 왜 앨리스 전대장의 얼굴을 하고 있는 건가!","JPN":"カルメン！　なぜ貴様がアリス戦隊長の格好をしているのだ！","ENG":"Carmen! Why do you have the face of Commander Alice?","TWN":"卡門！你為何偽裝成艾莉絲戰隊長的臉！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"웃……! 점잖지 못하게, 무차별로 쏟아붓긴……!","JPN":"うっ……！　大人げないわね。無差別に爆撃するなんて……！","ENG":"Ugh..! Such indecent, indiscriminate firing...!","TWN":"唔……！竟然這樣不管三七二十一地亂發射……！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 왜? 저쪽은 취향이 아니야?","JPN":"ふふっ、どうしたの？　あっちは趣味じゃない？","ENG":"Fuu fuu, what’s wrong? Isn’t that your type?","TWN":"呵呵，幹嘛？你不喜歡嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"당연하지! 손도 안 닿는 곳에서 괴롭히는걸!","JPN":"もちろんよ！　手も届かない距離で苛めるんだもの！","ENG":"Of course not! She’s bullying me from out of my reach!","TWN":"那還用說！竟然從那麼遠的地方發動攻擊！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라, 어떻게 여기까지 온 거야? 재조정이니 하지 않았어?","JPN":"リュドミラちゃん、どうやってここまで来たの？ 　再調整とか言ってなかった？","ENG":"Lyudmila, how did you get here? Didn’t you say you were readjusting?","TWN":"盧德米拉，你怎麼會來？不是在重整嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음. 관리자님께 상황을 전달 받고 강력하게 중단을 요청드렸다.","JPN":"うむ。管理者殿から状況を聞き、断固中断することを要請した。","ENG":"Well. The Administrator informed me about the situation and I requested for the halt.","TWN":"嗯，我從管理者那裡收到消息後，便強烈要求暫停。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 뭐? 진통제도 안 듣는 주제에 또 고집 부렸어?","JPN":"ちょっと、何だって？　鎮痛剤も聞かないくせにまた意地を張ったの？","ENG":"What? Did you dig in your heels again? Your body doesn’t even respond to painkillers!","TWN":"你說什麼？鎮痛劑都還沒發揮效果，你就又恣意妄為嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"항상 최상의 상태로 전쟁을 수행할 수 있다는 보장은 없다. 전력은 늘 한정되어 있어.","JPN":"いつも最適の状態で戦争をこなせるという保証はない。戦力はいつも限られているんだ。","ENG":"There is no guarantee that one will always be able to do battle in the best possible condition. One’s power is always limited in some fashion.","TWN":"我的戰力有限，不保證能以最佳狀態上戰場。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다 신뢰하는 전우들을 도와야 하는데 그것이 중요한가?","JPN":"なにより、信頼している戦友を助けなければならないのにそれが大事か？","ENG":"But above all, I must help my trusted comrades, is that not most important?","TWN":"不過重點是要幫助我信賴的戰友，其他不重要吧？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이 머릿속에 전술 교리만 들어찬 바보가 진짜……","JPN":"まったく、頭に戦術の教えばかり入っているバカが……","ENG":"Ugh, this idiot, with all this stereotypical war commander nonsense...","TWN":"你這個腦子只有戰術的傻瓜……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저게 어떤 녀석인지 그새 잊었어? 몇 명 온다고 끝날 일이 아니라고!","JPN":"あれが何なのかもう忘れたの？　何人来たところで済むことじゃないのよ！","ENG":"Have you forgotten what level of enemy this is? We aren’t going to be able to take care of this with just a few people arriving!","TWN":"你忘記對方是什麼樣的傢伙嗎？就算加上你們幾個事情也無法解決的！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금 전력만으로는 버거운 상대임은 잘 알고 있다.","JPN":"今の戦力だけでは手ごわい相手であることは承知している。","ENG":"Even in our present state, I understand that she is a formidable opponent.","TWN":"我很清楚，光憑現在的戰力很可能不是她的對手。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만…... 그렇다고 전우 곁을 떠나는 군인의 덕목을 나는 배운 적 없어, 알렉스.","JPN":"でも……だからといって戦友を置いて逃げるということを、私は習ったことがないんだ、アレックス。","ENG":"However... I have never learned to ever abandon my comrades, Alex.","TWN":"但是……難道因為這樣就要拋下戰友嗎？這不是我所學的軍人之道，雅蕾克絲。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"OPERATOR_NPC_NULL_A","text":{"KOREA":"마에스트로 네퀴티아. 콜드 케이스 137번과 대치 중입니다.","JPN":"マエストロ・ネキティア。コールドケース137番と対峙中です。","ENG":"Maestra Nequitia. Cold Case #137 is being confronted.","TWN":"指揮家 莉奎蒂亞，和Cold Case 137號對峙中。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OPERATOR_NPC_NULL_A","text":{"KOREA":"아군의 공세가 계속 이어지고 있으나……! 피해를 입은 사실은 확인되지 않습니다!","JPN":"味方の攻勢が続いておりますが……！　ダメージを受けたのかは確認できません！","ENG":"Our attack continues...! But no damage is confirmed!","TWN":"雖然我方持續發動攻勢……！但沒有證據顯示有造成傷害！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};